(3, 'Aurora Borealis', 'bg-aurora-new', '#001a1a', 'radial-gradient(circle at 50% 50%, rgba(0, 255, 170, 0.4), rgba(0, 100, 255, 0.4), #000)', '@keyframes bg-aurora-new { 0% { transform: scale(1) rotate(0deg); } 50% { transform: scale(1.2) rotate(180deg); } 100% { transform: scale(1) rotate(360deg); } }', 1),
