(5, 'Cinematic Blur', 'bg-cinematic', '#0f172a', 'linear-gradient(to bottom, rgba(15,23,42,0.8), rgba(15,23,42,0.95))', '@keyframes bg-cinematic-pulse { 0% { opacity: 0.8; transform: scale(1); } 50% { opacity: 1; transform: scale(1.05); } 100% { opacity: 0.8; transform: scale(1); } }', 1),
