INSERT INTO `sys_clocks` (`id`, `name`, `type`, `css_style`, `css_code`, `svg_code`, `is_active`) VALUES
(1, 'Minimalist Glass', 'digital', 'clock-glass', 'background: rgba(255, 255, 255, 0.1); backdrop-filter: blur(10px); border: 1px solid rgba(255,255,255,0.2); color: #fff; padding: 10px 20px; border-radius: 12px; font-family: \"Inter\", sans-serif; font-weight: 600; box-shadow: 0 8px 32px rgba(0,0,0,0.2);', NULL, 1),
(2, 'Neon Cyber Glow', 'digital', 'clock-cyber', 'background: rgba(0,0,0,0.8); color: #00e5ff; padding: 10px 20px; border-radius: 8px; font-family: \"Space Mono\", monospace; font-weight: 700; border: 1px solid #00e5ff; box-shadow: 0 0 10px #00e5ff, inset 0 0 10px #00e5ff;', NULL, 1),
(3, 'Classic Swiss', 'analog', 'clock-swiss', 'width: 150px; height: 150px; background: #fff; border-radius: 50%; border: 4px solid #333; box-shadow: 0 10px 25px rgba(0,0,0,0.3); position: relative;', '<svg viewBox=\"0 0 100 100\" width=\"100%\" height=\"100%\"><circle cx=\"50\" cy=\"50\" r=\"48\" fill=\"#fff\"/><line x1=\"50\" y1=\"50\" x2=\"50\" y2=\"20\" stroke=\"#000\" stroke-width=\"4\" stroke-linecap=\"round\" class=\"hour-hand\"/><line x1=\"50\" y1=\"50\" x2=\"50\" y2=\"10\" stroke=\"#000\" stroke-width=\"3\" stroke-linecap=\"round\" class=\"minute-hand\"/><line x1=\"50\" y1=\"60\" x2=\"50\" y2=\"10\" stroke=\"#e53935\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"second-hand\"/><circle cx=\"50\" cy=\"50\" r=\"3\" fill=\"#e53935\"/></svg>', 1),
(4, 'Modern Gradient', 'digital', 'clock-gradient', 'background: transparent; font-family: \"Inter\", sans-serif; font-weight: 800; font-size: 3rem; background: linear-gradient(45deg, #ff007a, #ff9900); -webkit-background-clip: text; -webkit-text-fill-color: transparent; filter: drop-shadow(0px 4px 6px rgba(0,0,0,0.4));', NULL, 1),
(5, 'Retro Flip-Clock', 'digital', 'clock-flip', 'background: #111; color: #fff; padding: 15px 25px; border-radius: 12px; font-family: \"Inter\", sans-serif; font-weight: 800; font-size: 2.5rem; letter-spacing: 2px; box-shadow: 0 10px 30px rgba(0,0,0,0.5); border-top: 2px solid #333; position: relative;', NULL, 1),
(6, 'Dark Elegance', 'analog', 'clock-dark-elegance', 'width: 150px; height: 150px; background: transparent; border-radius: 50%; box-shadow: 0 10px 25px rgba(0,0,0,0.5); position: relative;', '<svg viewBox=\"0 0 100 100\" width=\"100%\" height=\"100%\"><circle cx=\"50\" cy=\"50\" r=\"48\" fill=\"#1f2937\"/><line x1=\"50\" y1=\"50\" x2=\"50\" y2=\"25\" stroke=\"#cbd5e1\" stroke-width=\"3\" stroke-linecap=\"round\" class=\"hour-hand\"/><line x1=\"50\" y1=\"50\" x2=\"50\" y2=\"15\" stroke=\"#cbd5e1\" stroke-width=\"2\" stroke-linecap=\"round\" class=\"minute-hand\"/><line x1=\"50\" y1=\"60\" x2=\"50\" y2=\"10\" stroke=\"#fbbf24\" stroke-width=\"1\" stroke-linecap=\"round\" class=\"second-hand\"/><circle cx=\"50\" cy=\"50\" r=\"2\" fill=\"#fbbf24\"/></svg>', 1),
(7, 'Industrial Steel', 'digital', 'clock-industrial', 'background: linear-gradient(135deg, #475569, #1e293b); color: #f97316; padding: 12px 24px; border-radius: 4px; font-family: \"Space Mono\", monospace; font-weight: 700; border: 2px solid #64748b; box-shadow: 4px 4px 0px rgba(0,0,0,0.5);', NULL, 1),
(8, 'Subtle Floating', 'digital', 'clock-floating', 'background: transparent; color: #ffffff; font-family: \"Inter\", sans-serif; font-weight: 400; font-size: 2.5rem; text-shadow: 0px 4px 10px rgba(0,0,0,0.6);', NULL, 1),
(9, 'Bauhaus Analog', 'analog', 'clock-bauhaus', 'width: 150px; height: 150px; background: transparent; border-radius: 50%; box-shadow: 0 10px 25px rgba(0,0,0,0.2); position: relative;', '<svg viewBox=\"0 0 100 100\" width=\"100%\" height=\"100%\"><circle cx=\"50\" cy=\"50\" r=\"48\" fill=\"#f8fafc\"/><rect x=\"48\" y=\"5\" width=\"4\" height=\"10\" fill=\"#0f172a\"/><rect x=\"48\" y=\"85\" width=\"4\" height=\"10\" fill=\"#0f172a\"/><rect x=\"5\" y=\"48\" width=\"10\" height=\"4\" fill=\"#0f172a\"/><rect x=\"85\" y=\"48\" width=\"10\" height=\"4\" fill=\"#0f172a\"/><line x1=\"50\" y1=\"50\" x2=\"50\" y2=\"20\" stroke=\"#0f172a\" stroke-width=\"5\" class=\"hour-hand\"/><line x1=\"50\" y1=\"50\" x2=\"50\" y2=\"10\" stroke=\"#0f172a\" stroke-width=\"3\" class=\"minute-hand\"/><line x1=\"50\" y1=\"50\" x2=\"50\" y2=\"10\" stroke=\"#ef4444\" stroke-width=\"1.5\" class=\"second-hand\"/><circle cx=\"50\" cy=\"50\" r=\"3\" fill=\"#ef4444\"/></svg>', 1),
(10, 'Digital Dot-Matrix', 'digital', 'clock-matrix', 'background: #000; color: #22c55e; padding: 10px 20px; border-radius: 6px; font-family: \"Space Mono\", monospace; font-weight: 700; font-size: 2rem; border: 2px solid #064e3b; letter-spacing: 4px;', NULL, 1);
